/* Types */
/**
 *  Typed command error taxonomy for Tauri command boundary.
 * 
 *  Serializes to {"code": "...", "message": "..."} for frontend discriminated union handling.
 */
export type CommandError = { code: "NotFound"; message: string } | { code: "InternalError"; message: string } | { code: "Timeout"; message: string } | { code: "Cancelled"; message: string } | { code: "ValidationError"; message: string } | { code: "Conflict"; message: string };

/**
 *  Frontend-facing daemon-bootstrap failure payload. `detail` carries the
 *  original error message (English, already user-safe) for diagnostics; the
 *  version fields are populated only for
 *  [`DaemonBootstrapFailureKind::VersionTooOld`].
 */
export type DaemonBootstrapFailure = {
	kind: DaemonBootstrapFailureKind,
	detail: string,
	observedVersion: string | null,
	expectedVersion: string | null,
};

/**
 *  Machine-readable classification of a daemon-bootstrap failure, surfaced to
 *  the frontend so it can show an actionable message instead of an endless
 *  loading screen. `bootstrap_daemon_in_process` only populates the daemon
 *  connection state on success; on failure the connection stays unset, so
 *  without this signal the frontend's `get_daemon_connection_info` poll would
 *  just spin until its own timeout.
 */
export type DaemonBootstrapFailureKind = 
/**
 *  The running daemon is a strictly-newer version than this GUI client.
 *  ADR-008 P4-7 downgrade protection refuses to take it over, so the fix is
 *  to update the app — a distinct kind so the UI can say "update" rather
 *  than "restart".
 */
"versionTooOld" | 
/**
 *  Any other terminal bootstrap failure (spawn failure, health-check
 *  timeout, probe error, or an older-or-equal daemon that couldn't be
 *  replaced).
 */
"unavailable";

export type DaemonConnectionPayload = {
	baseUrl: string,
	wsUrl: string,
};

export type DaemonSessionPayload = {
	sessionToken: string,
	expiresInSecs: number,
	refreshAtSecs: number,
};

/**
 *  暴露给 webview 的设备和应用元数据，用于补齐前端 Sentry scope。
 * 
 *  字段命名与后端 `ScopeContext` 一一对应（`device.id` / `device.role` /
 *  `device.platform` / `app.version` / `app.channel`）。webview 侧的
 *  `device.role` 默认仍是 `webview`，这里返回的 `device_role` 是 *Rust 主进程*
 *  的角色（`gui-host`），webview 把它打到 `device.host_role` 二级 tag 上,
 *  便于 Sentry 上同时看到两端。
 */
export type DeviceMeta = {
	deviceId: string,
	deviceRole: string,
	platform: string,
	appVersion: string,
	appChannel: string,
};

/**
 *  Events emitted during update download.
 * 
 *  Carried both via the broadcast `UPDATE_PROGRESS_EVENT` (background
 *  download) and via the per-invocation `Channel<DownloadEvent>` passed to
 *  `install_update` (legacy combined download+install path).
 */
export type DownloadEvent = { event: "Started"; data: {
	contentLength: number | null,
} } | { event: "Progress"; data: {
	chunkLength: number,
} } | { event: "Finished" } | { event: "Failed"; data: {
	error: string,
} };

/**
 *  Coarse-grained phase used by `get_download_progress` so a frontend that
 *  mounts mid-download can render the right icon variant.
 */
export type DownloadPhase = "idle" | "available" | "downloading" | "ready";

/**
 *  Snapshot of current download state, queryable from the frontend so a
 *  just-mounted listener can sync up before attaching to the event stream.
 */
export type DownloadProgressSnapshot = {
	phase: DownloadPhase,
	downloaded: number,
	total: number | null,
	/**  Newly-available (latest) version. `None` when phase is `Idle`. */
	version: string | null,
	/**
	 *  Currently-installed app version, lifted directly from
	 *  `app.package_info().version`. Always populated even when phase is
	 *  `Idle`, so a mid-mount frontend can render "current vs. latest"
	 *  without waiting for a fresh `check_for_update` round-trip.
	 */
	currentVersion: string,
	/**
	 *  Release notes for the available version, if any. `None` when phase
	 *  is `Idle` or the release ships no notes.
	 */
	body: string | null,
	/**
	 *  Release date for the available version, if any. `None` when phase
	 *  is `Idle`.
	 */
	date: string | null,
};

/**
 *  Installation provenance of the running binary.
 * 
 *  Used by the frontend to short-circuit in-app update when the user is on a
 *  system-packaged Linux build: Tauri's Linux updater only supports
 *  AppImage, so deb/rpm users must be routed to their package manager.
 */
export type InstallKind = "macos" | "windows" | 
/**
 *  Windows portable ("green") zip. The in-app updater would try to run the
 *  NSIS installer, which installs into Program Files rather than updating
 *  the portable folder — so the frontend routes this kind to a
 *  "download the new portable zip" dialog instead of self-installing.
 */
"windowsportable" | "appimage" | "deb" | "rpm" | "unknown";

/**
 *  Which side the inline preview opens toward (Tauri command wire form).
 * 
 *  wire form: `right` | `left`.
 */
export type QuickPanelExpandSide = "right" | "left";

/**
 *  Quick panel placement preference (Tauri command wire form).
 * 
 *  wire form: `center` | `follow_cursor`.
 */
export type QuickPanelPositionArg = "center" | "follow_cursor";

/**
 *  一次 `probe_relay_url` 调用的细分结果。
 * 
 *  探测失败属于"用户可以理解的预期场景"(URL 写错、对端 DNS 不可达、TLS
 *  不可信等),所以这些状态以 `Ok(outcome)` 的形式返回,让前端可以在不抛
 *  异常的前提下区分文案。系统级故障(facade 缺失装配、trace 解析失败等)
 *  仍然走 [`CommandError`]。
 */
export type RelayProbeOutcome = { kind: "success"; latencyMs: number } | { kind: "invalidUrl"; message: string } | { kind: "dns"; message: string } | { kind: "tls"; message: string } | { kind: "handshake"; message: string } | { kind: "timeout" } | { kind: "other"; message: string };

export type ShortcutKeyDto = string | string[];

export type TraceMetadata = {
	trace_id: string,
	timestamp: number,
};

export type UpdateKeyboardShortcutsResult = {
	keyboardShortcuts: { [key in string]: ShortcutKeyDto },
};

/**  Metadata returned to the frontend when an update is available. */
export type UpdateMetadata = {
	version: string,
	currentVersion: string,
	body: string | null,
	date: string | null,
};

/* Tauri Specta runtime */
async function typedError<T, E>(result: Promise<T>): Promise<{ status: "ok"; data: T } | { status: "error"; error: E }> {
    try {
        return { status: "ok", data: await result };
    } catch (e) {
        if (e instanceof Error) throw e;
        return { status: "error", error: e as any };
    }
}

